vy: #000864; }\n\n/* Blog base CSS (extracted from styles.css) */\n.blog-hero {\n    background: linear-gradient(135deg, #0f1419 0%, #000432 40%, #000864 100%);\n    padding: 160px 24px 60px;\n    position: relative;\n    overflow: hidden;\n}\n.blog-hero::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n    pointer-events: none;\n}\n.blog-hero-inner {\n    max-width: 800px;\n    margin: 0 auto;\n    position: relative;\n    z-index: 1;\n}\n.blog-back-link {\n    display: inline-flex;\n    align-items: center;\n    gap: 6px;\n    color: rgba(255,255,255,0.85);\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 15px;\n    font-weight: 500;\n    text-decoration: none;\n    transition: color 0.3s ease;\n}\n.blog-back-link:hover {\n    color: #00AFF0;\n}\n.blog-back-link svg {\n    width: 16px;\n    height: 16px;\n    stroke: currentColor;\n}\n.blog-category-badge {\n    display: inline-block;\n    font-family: \'JetBrains Mono\', monospace;\n    font-size: 11px;\n    font-weight: 500;\n    letter-spacing: 0.1em;\n    text-transform: uppercase;\n    color: #fff;\n    padding: 5px 12px;\n    border-radius: 4px;\n}\n.blog-hero h1 {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: clamp(28px, 4.5vw, 42px);\n    font-weight: 700;\n    color: #fff;\n    line-height: 1.2;\n    margin-bottom: 20px;\n}\n.blog-meta {\n    font-family: \'Noto Sans\', sans-serif;\n    font-size: 15px;\n    color: rgba(255,255,255,0.85);\n    display: flex;\n    align-items: center;\n    gap: 12px;\n}\n.blog-meta-dot {\n    width: 4px;\n    height: 4px;\n    border-radius: 50%;\n    background: rgba(255,255,255,0.3);\n}\n.blog-body {\n    max-width: 760px;\